using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public sealed class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class ModelTrainerService
{
    private readonly ILogger<ModelTrainerService> _logger;

    public ModelTrainerService(ILogger<ModelTrainerService> logger)
    {
        _logger = logger;
    }

    public string TrainAndSaveModel(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurize text columns and combine with Priority into a single Features vector
        var pipeline = mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on the test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        var report = $"""
            === Model Evaluation Metrics ===
            MicroAccuracy:  {metrics.MicroAccuracy:F4}
            MacroAccuracy:  {metrics.MacroAccuracy:F4}
            LogLoss:        {metrics.LogLoss:F4}
            LogLossReduction: {metrics.LogLossReduction:F4}
            """;

        _logger.LogInformation("{Metrics}", report);

        mlContext.Model.Save(model, data.Schema, modelPath);
        _logger.LogInformation("Model saved to {Path}", modelPath);

        return report;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly ModelTrainerService _trainer;

    public TicketController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        ModelTrainerService trainer)
    {
        _predictionPool = predictionPool;
        _trainer = trainer;
    }

    [HttpPost("classify")]
    public ActionResult<object> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        return Ok(new
        {
            prediction.PredictedCategory,
            Confidence = prediction.Score.Max(),
        });
    }

    [HttpPost("train")]
    public ActionResult<object> Train()
    {
        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");

        var report = _trainer.TrainAndSaveModel(dataPath, modelPath);

        return Ok(new { Message = "Model trained successfully.", Metrics = report });
    }
}

